using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Adjust the namespace according to your project
using System.Web.Security;

public class ReviewsController : Controller
{
    private YourDbContext db = new YourDbContext(); // Replace with your actual DbContext

    public ActionResult ProductReviews(int productId)
    {
        var reviews = db.Reviews.Where(r => r.ProductId == productId).ToList();
        return View(reviews);
    }

    [HttpPost]
    [ValidateAntiForgeryToken]
    public ActionResult SubmitReview(Review review)
    {
        if (ModelState.IsValid)
        {
            db.Reviews.Add(review);
            db.SaveChanges();
            return RedirectToAction("ProductReviews", new { productId = review.ProductId });
        }
        return View(review);
    }
}

// Razor View (ProductReviews.cshtml)
@model IEnumerable<YourNamespace.Models.Review>

<h2>Product Reviews</h2>

@using (Html.BeginForm("SubmitReview", "Reviews", FormMethod.Post))
{
    @Html.AntiForgeryToken()
    <div>
        @Html.TextAreaFor(m => m.ReviewText, new { @placeholder = "Write your review here..." })
    </div>
    <button type="submit">Submit Review</button>
}

@foreach (var review in Model)
{
    <div>
        <strong>@Html.DisplayFor(m => review.UserName)</strong>
        <p>@Html.Raw(HttpUtility.HtmlEncode(review.ReviewText))</p>
    </div>
}